import { useEffect, useState } from "react";

interface StatefulController<T> {
  state$: { subscribe: (cb: (v: T) => void) => { unsubscribe: () => void } };
  getState(): T;
}

export function useControllerState<T>(controller: StatefulController<T>): T {
  const [state, setState] = useState(controller.getState());

  useEffect(() => {
    const subscription = controller.state$.subscribe(setState);
    return () => subscription.unsubscribe();
  }, [controller]);

  return state;
}
