import buttonClasses from "../view/react/components/button/button.module.css";
import authClasses from "./auth.module.css";
import { useAuth } from "./AuthProvider";

export function LoginScreen() {
  const { signInWithGoogle } = useAuth();

  return (
    <div className={authClasses.Screen}>
      <div className={authClasses.Panel}>
        <h1 className={authClasses.Title}>Todo Quest</h1>
        <p className={authClasses.Text}>Sign in to continue your quest.</p>
        <button className={buttonClasses.Button} onClick={signInWithGoogle}>
          Sign in with Google
        </button>
      </div>
    </div>
  );
}
