import type { Goal } from "../../core/entities/Goal";
import type { CreateGoalError } from "../../core/errors/goal-errors";
import type { IGoalRepo } from "../../core/ports/IGoalRepo";
import { Subject, type Observable } from "../../libs/rx";
import { container } from "../../utils/container";

class CreateGoalController {
  handleCreateGoal(goal: Goal): Promise<void | CreateGoalError> {
    const goalRepo = container.resolve("goalRepo");
    return goalRepo.createGoal(goal);
  }
  handleCancelCreateGoal(): void {
    this._cancelCreateGoal.next();
  }
  private _cancelCreateGoal = new Subject<void>();

  get cancelCreateGoal$(): Observable<void> {
    return this._cancelCreateGoal.asObservable();
  }
}

export { CreateGoalController };
