import type { Goal } from "../core/entities/Goal";
import type { IGoalRepo } from "../core/ports/IGoalRepo";
import {
  CreateGoalError,
  DeleteGoalError,
  LoadGoalsError,
} from "../core/errors/goal-errors";
import { apiBaseUrl } from "./apiBaseUrl";
import { authFetch } from "./authFetch";

class GoalRepo implements IGoalRepo {
  async getGoals(): Promise<Goal[] | LoadGoalsError> {
    try {
      const res = await authFetch(`${apiBaseUrl}/api/goals`);
      if (!res.ok) {
        return new LoadGoalsError("Failed to load goals");
      }
      const data = (await res.json()) as { goals: Goal[] };
      return data.goals;
    } catch {
      return new LoadGoalsError("Failed to load goals");
    }
  }

  async createGoal(goal: Goal): Promise<void | CreateGoalError> {
    try {
      const res = await authFetch(`${apiBaseUrl}/api/goals`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: goal.name }),
      });
      if (!res.ok) {
        return new CreateGoalError("Failed to create goal");
      }
    } catch {
      return new CreateGoalError("Failed to create goal");
    }
  }

  async deleteGoal(id: string): Promise<void | DeleteGoalError> {
    try {
      const res = await authFetch(`${apiBaseUrl}/api/goals/${id}`, {
        method: "DELETE",
      });
      if (!res.ok) {
        return new DeleteGoalError("Failed to delete goal");
      }
    } catch {
      return new DeleteGoalError("Failed to delete goal");
    }
  }
}
export { GoalRepo };
