import type { Task } from "../core/entities/Task";
import type { ITaskRepo } from "../core/ports/ITaskRepo";
import {
  CreateTaskError,
  DeleteTaskError,
  LoadTasksError,
  ToggleTaskError,
} from "../core/errors/task-errors";
import { apiBaseUrl } from "./apiBaseUrl";
import { authFetch } from "./authFetch";

class TaskRepo implements ITaskRepo {
  async getTasks(goalId: string): Promise<Task[] | LoadTasksError> {
    try {
      const res = await authFetch(`${apiBaseUrl}/api/goals/${goalId}/tasks`);
      if (!res.ok) {
        return new LoadTasksError("Failed to load tasks");
      }
      const data = (await res.json()) as { tasks: Task[] };
      return data.tasks;
    } catch {
      return new LoadTasksError("Failed to load tasks");
    }
  }

  async createTask(task: Task): Promise<void | CreateTaskError> {
    try {
      const res = await authFetch(`${apiBaseUrl}/api/goals/${task.goalId}/tasks`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: task.name }),
      });
      if (!res.ok) {
        return new CreateTaskError("Failed to create task");
      }
    } catch {
      return new CreateTaskError("Failed to create task");
    }
  }

  async deleteTask(id: string): Promise<void | DeleteTaskError> {
    try {
      const res = await authFetch(`${apiBaseUrl}/api/tasks/${id}`, {
        method: "DELETE",
      });
      if (!res.ok) {
        return new DeleteTaskError("Failed to delete task");
      }
    } catch {
      return new DeleteTaskError("Failed to delete task");
    }
  }

  async toggleTask(
    id: string,
    completed: boolean
  ): Promise<void | ToggleTaskError> {
    try {
      const res = await authFetch(`${apiBaseUrl}/api/tasks/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ completed }),
      });
      if (!res.ok) {
        return new ToggleTaskError("Failed to update task");
      }
    } catch {
      return new ToggleTaskError("Failed to update task");
    }
  }
}
export { TaskRepo };
