import type { Goal } from "../../core/entities/Goal";
import { LoadGoalsError } from "../../core/errors/goal-errors";
import { BehaviorSubject } from "../../libs/rx";
import { container } from "../../utils/container";

interface State {
  goals: Goal[];
}

const initialState: State = {
  goals: [],
};

class ListGoalsController {
  async loadGoals(): Promise<void | LoadGoalsError> {
    const goalRepo = container.resolve("goalRepo");
    const goalsResult = await goalRepo.getGoals();

    if (goalsResult instanceof LoadGoalsError) {
      return goalsResult;
    }

    this._state.next({
      ...this._state.value,
      goals: goalsResult as Goal[],
    });
  }
  removeGoal(goalId: string): void {
    this._state.next({
      ...this._state.value,
      goals: this._state.value.goals.filter((goal) => goal.id !== goalId),
    });
  }
  private _state = new BehaviorSubject<State>(initialState);

  get state$() {
    return this._state.asObservable();
  }
  getState(): State {
    return this._state.value;
  }
}

export { ListGoalsController };
