import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import type { Session } from "@supabase/supabase-js";
import { supabase } from "./supabaseClient";
import { googleSignInStrategy } from "./googleSignInStrategy";

export type AuthStatus =
  | "loading"
  | "signedOut"
  | "checking"
  | "allowed"
  | "denied";

interface AuthContextValue {
  status: AuthStatus;
  email: string | null;
  contactEmail: string | null;
  signInWithGoogle: () => Promise<void>;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextValue | null>(null);

const apiUrl = process.env.BUN_PUBLIC_API_URL ?? "http://localhost:8787";

async function fetchAccess(
  accessToken: string
): Promise<{ allowed: boolean; contactEmail: string }> {
  const res = await fetch(`${apiUrl}/api/auth/me`, {
    headers: { Authorization: `Bearer ${accessToken}` },
  });

  if (!res.ok) {
    return { allowed: false, contactEmail: "contact@example.com" };
  }

  return res.json();
}

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [status, setStatus] = useState<AuthStatus>("loading");
  const [email, setEmail] = useState<string | null>(null);
  const [contactEmail, setContactEmail] = useState<string | null>(null);
  const checkedTokenRef = useRef<string | null>(null);

  useEffect(() => {
    async function resolveSession(session: Session | null) {
      if (!session) {
        checkedTokenRef.current = null;
        setStatus("signedOut");
        setEmail(null);
        return;
      }

      if (checkedTokenRef.current === session.access_token) return;
      checkedTokenRef.current = session.access_token;

      setStatus("checking");
      setEmail(session.user.email ?? null);

      const access = await fetchAccess(session.access_token);
      setContactEmail(access.contactEmail);
      setStatus(access.allowed ? "allowed" : "denied");
    }

    supabase.auth.getSession().then(({ data }) => resolveSession(data.session));

    const { data: subscription } = supabase.auth.onAuthStateChange(
      (_event, session) => {
        resolveSession(session);
      }
    );

    return () => subscription.subscription.unsubscribe();
  }, []);

  const value = useMemo<AuthContextValue>(
    () => ({
      status,
      email,
      contactEmail,
      signInWithGoogle: () => googleSignInStrategy.signIn(),
      signOut: async () => {
        await supabase.auth.signOut();
      },
    }),
    [status, email, contactEmail]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth(): AuthContextValue {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}
