import { useEffect, useState } from "react";
import { Dialog, Form } from "radix-ui";
import { Cross2Icon } from "@radix-ui/react-icons";
import "./index.css";
import dialogClasses from "./components/dialog/dialog.module.css";
import buttonClasses from "./components/button/button.module.css";
import formClasses from "./components/form/form.module.css";
import headerClasses from "./components/header/header.module.css";
import { GoalsList } from "./features/goals/GoalsList";
import { useControllerState } from "./hooks/useControllerState";
import { container } from "../../utils/container";
import { useAuth } from "../../auth/AuthProvider";

export function App() {
  const { signOut } = useAuth();
  const listGoalsController = container.resolve("listGoalsController");
  const menuController = container.resolve("menuController");
  const createGoalController = container.resolve("createGoalController");
  const deleteGoalController = container.resolve("deleteGoalController");
  const listTasksController = container.resolve("listTasksController");
  const createTaskController = container.resolve("createTaskController");
  const deleteTaskController = container.resolve("deleteTaskController");
  const toggleTaskController = container.resolve("toggleTaskController");

  const { goals } = useControllerState(listGoalsController);
  const { showCreateGoalForm } = useControllerState(menuController);
  const { tasksByGoalId } = useControllerState(listTasksController);

  const [name, setName] = useState("");
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    listGoalsController.loadGoals();
  }, []);

  function handleOpenChange(open: boolean) {
    if (open) {
      menuController.handleCreateGoal();
    } else {
      createGoalController.handleCancelCreateGoal();
    }
  }

  async function handleSubmit(event: React.FormEvent) {
    event.preventDefault();
    setSubmitting(true);

    const result = await createGoalController.handleCreateGoal({
      id: crypto.randomUUID(),
      name,
    });

    setSubmitting(false);

    if (!(result instanceof Error)) {
      setName("");
      await listGoalsController.loadGoals();
      createGoalController.handleCancelCreateGoal();
    }
  }

  async function handleDeleteGoal(goalId: string) {
    const result = await deleteGoalController.handleDeleteGoal(goalId);

    if (!(result instanceof Error)) {
      listGoalsController.removeGoal(goalId);
    }

    return result;
  }

  async function handleExpandGoal(goalId: string) {
    return listTasksController.loadTasks(goalId);
  }

  async function handleAddTask(goalId: string, name: string) {
    const task = { id: crypto.randomUUID(), goalId, name, completed: false };
    const result = await createTaskController.handleCreateTask(task);

    if (!(result instanceof Error)) {
      listTasksController.addTask(goalId, task);
    }

    return result;
  }

  async function handleDeleteTask(goalId: string, taskId: string) {
    const result = await deleteTaskController.handleDeleteTask(taskId);

    if (!(result instanceof Error)) {
      listTasksController.removeTask(goalId, taskId);
    }

    return result;
  }

  async function handleToggleTask(
    goalId: string,
    taskId: string,
    completed: boolean
  ) {
    const result = await toggleTaskController.handleToggleTask(
      taskId,
      completed
    );

    if (!(result instanceof Error)) {
      listTasksController.setTaskCompleted(goalId, taskId, completed);
    }

    return result;
  }

  return (
    <div className="app">
      <header className={headerClasses.Header}>
        <h1 className={headerClasses.Title}>Todo Quest</h1>
        <button
          className={`${buttonClasses.Button} ${headerClasses.SignOutButton}`}
          onClick={signOut}
        >
          Sign out
        </button>
      </header>
      <Dialog.Root open={showCreateGoalForm} onOpenChange={handleOpenChange}>
        <Dialog.Trigger asChild>
          <button style={{ margin: "10px" }} className={buttonClasses.Button}>
            + New goal
          </button>
        </Dialog.Trigger>
        <Dialog.Portal>
          <Dialog.Overlay className={dialogClasses.DialogOverlay}>
            <Dialog.Content className={dialogClasses.DialogContent}>
              <Dialog.Title className={dialogClasses.DialogTitle}>
                New goal
              </Dialog.Title>
              <Form.Root className={formClasses.Form} onSubmit={handleSubmit}>
                <Form.Field className={formClasses.Field} name="name">
                  <div>
                    <Form.Label className={formClasses.Label}>Name</Form.Label>
                  </div>
                  <Form.Control asChild>
                    <input
                      className={formClasses.Input}
                      type="text"
                      value={name}
                      onChange={(event) => setName(event.target.value)}
                      required
                    />
                  </Form.Control>
                </Form.Field>
                <Form.Submit
                  className={buttonClasses.Button}
                  disabled={submitting}
                  asChild
                >
                  <button>Create goal</button>
                </Form.Submit>
              </Form.Root>
              <Dialog.Close className={dialogClasses.DialogClose} asChild>
                <button aria-label="Close">
                  <Cross2Icon />
                </button>
              </Dialog.Close>
            </Dialog.Content>
          </Dialog.Overlay>
        </Dialog.Portal>
      </Dialog.Root>
      <GoalsList
        goals={goals}
        tasksByGoalId={tasksByGoalId}
        onDeleteGoal={handleDeleteGoal}
        onExpandGoal={handleExpandGoal}
        onAddTask={handleAddTask}
        onDeleteTask={handleDeleteTask}
        onToggleTask={handleToggleTask}
      />
    </div>
  );
}

export default App;
