import type { Task } from "../../core/entities/Task";
import { LoadTasksError } from "../../core/errors/task-errors";
import { BehaviorSubject } from "../../libs/rx";
import { container } from "../../utils/container";

interface State {
  tasksByGoalId: Record<string, Task[]>;
}

const initialState: State = {
  tasksByGoalId: {},
};

class ListTasksController {
  async loadTasks(goalId: string): Promise<void | LoadTasksError> {
    const taskRepo = container.resolve("taskRepo");
    const tasksResult = await taskRepo.getTasks(goalId);

    if (tasksResult instanceof LoadTasksError) {
      return tasksResult;
    }

    this._state.next({
      ...this._state.value,
      tasksByGoalId: {
        ...this._state.value.tasksByGoalId,
        [goalId]: tasksResult as Task[],
      },
    });
  }
  addTask(goalId: string, task: Task): void {
    const existingTasks = this._state.value.tasksByGoalId[goalId] ?? [];

    this._state.next({
      ...this._state.value,
      tasksByGoalId: {
        ...this._state.value.tasksByGoalId,
        [goalId]: [...existingTasks, task],
      },
    });
  }
  removeTask(goalId: string, taskId: string): void {
    const existingTasks = this._state.value.tasksByGoalId[goalId] ?? [];

    this._state.next({
      ...this._state.value,
      tasksByGoalId: {
        ...this._state.value.tasksByGoalId,
        [goalId]: existingTasks.filter((task) => task.id !== taskId),
      },
    });
  }
  setTaskCompleted(goalId: string, taskId: string, completed: boolean): void {
    const existingTasks = this._state.value.tasksByGoalId[goalId] ?? [];

    this._state.next({
      ...this._state.value,
      tasksByGoalId: {
        ...this._state.value.tasksByGoalId,
        [goalId]: existingTasks.map((task) =>
          task.id === taskId ? { ...task, completed } : task
        ),
      },
    });
  }
  private _state = new BehaviorSubject<State>(initialState);

  get state$() {
    return this._state.asObservable();
  }
  getState(): State {
    return this._state.value;
  }
}

export { ListTasksController };
