import { useState } from "react";
import { Checkbox } from "radix-ui";
import { CheckIcon, Cross2Icon } from "@radix-ui/react-icons";
import type { Task } from "../../../../core/entities/Task";
import formClasses from "../../components/form/form.module.css";
import buttonClasses from "../../components/button/button.module.css";
import classes from "./goals.module.css";

interface Props {
  goalId: string;
  tasks: Task[];
  onAddTask: (goalId: string, name: string) => Promise<void | Error>;
  onDeleteTask: (goalId: string, taskId: string) => Promise<void | Error>;
  onToggleTask: (
    goalId: string,
    taskId: string,
    completed: boolean
  ) => Promise<void | Error>;
}

export function TaskList({
  goalId,
  tasks,
  onAddTask,
  onDeleteTask,
  onToggleTask,
}: Props) {
  const [taskName, setTaskName] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [pendingIds, setPendingIds] = useState<Set<string>>(new Set());

  function setPending(taskId: string, isPending: boolean) {
    setPendingIds((prev) => {
      const next = new Set(prev);
      if (isPending) {
        next.add(taskId);
      } else {
        next.delete(taskId);
      }
      return next;
    });
  }

  async function handleAddTask(event: React.FormEvent) {
    event.preventDefault();

    const name = taskName.trim();
    if (!name) {
      return;
    }

    setSubmitting(true);
    const result = await onAddTask(goalId, name);
    setSubmitting(false);

    if (!(result instanceof Error)) {
      setTaskName("");
    }
  }

  async function handleToggleTask(task: Task) {
    setPending(task.id, true);
    await onToggleTask(goalId, task.id, !task.completed);
    setPending(task.id, false);
  }

  async function handleDeleteTask(task: Task) {
    setPending(task.id, true);
    await onDeleteTask(goalId, task.id);
    setPending(task.id, false);
  }

  return (
    <div className={classes.TaskList}>
      {tasks.length === 0 ? (
        <p className={classes.EmptyTasks}>No objectives yet.</p>
      ) : (
        <ul className={classes.TaskItems}>
          {tasks.map((task) => {
            const isPending = pendingIds.has(task.id);

            return (
              <li key={task.id} className={classes.TaskItem}>
                <Checkbox.Root
                  className={classes.TaskCheckbox}
                  checked={task.completed}
                  disabled={isPending}
                  onCheckedChange={() => handleToggleTask(task)}
                >
                  <Checkbox.Indicator>
                    <CheckIcon />
                  </Checkbox.Indicator>
                </Checkbox.Root>
                <span
                  className={
                    task.completed
                      ? `${classes.TaskName} ${classes.TaskNameDone}`
                      : classes.TaskName
                  }
                >
                  {task.name}
                </span>
                <button
                  type="button"
                  aria-label="Delete task"
                  className={classes.DeleteTaskButton}
                  disabled={isPending}
                  onClick={() => handleDeleteTask(task)}
                >
                  <Cross2Icon />
                </button>
              </li>
            );
          })}
        </ul>
      )}
      <form className={classes.AddTaskForm} onSubmit={handleAddTask}>
        <input
          className={`${formClasses.Input} ${classes.AddTaskInput}`}
          type="text"
          placeholder="Add an objective..."
          value={taskName}
          onChange={(event) => setTaskName(event.target.value)}
        />
        <button
          type="submit"
          className={`${buttonClasses.Button} ${classes.AddTaskButton}`}
          disabled={submitting}
        >
          Add
        </button>
      </form>
    </div>
  );
}
